type BackendType = 'monolith' | 'microservices';

interface EnvironmentConfig {
  production: boolean;
  backendType: BackendType;
  apiBaseUrl: string;
  microservices: {
    defaultBaseUrl: string;
    services: {
      auth: string;
      users: string;
      admin: string;
      leaves: string;
      goals: string;
      performance: string;
    };
  };
}

export const environment: EnvironmentConfig = {
  production: false,
  backendType: 'monolith',
  apiBaseUrl: 'http://localhost:8080/api',
  microservices: {
    defaultBaseUrl: 'http://localhost:8080/api',
    services: {
      auth: 'http://localhost:8081/api',
      users: 'http://localhost:8082/api',
      admin: 'http://localhost:8082/api',
      leaves: 'http://localhost:8083/api',
      goals: 'http://localhost:8084/api',
      performance: 'http://localhost:8085/api'
    }
  }
};
